// Embedded Poppins (subset to Latin + punctuation) for the quote PDF.
// Regular + SemiBold, registered with jsPDF as the "Poppins" family.
// Generated by subsetting the OFL Poppins TTFs; do not hand-edit.
import type { jsPDF } from "jspdf";

const POPPINS_REGULAR =
  "";

const POPPINS_SEMIBOLD =
  "";

let registered = false;

/** Registers Poppins on a jsPDF doc so "Poppins" can be used as a font. */
export function registerQuoteFont(doc: jsPDF) {
  doc.addFileToVFS("Poppins-Regular.ttf", POPPINS_REGULAR);
  doc.addFont("Poppins-Regular.ttf", "Poppins", "normal");
  doc.addFileToVFS("Poppins-SemiBold.ttf", POPPINS_SEMIBOLD);
  doc.addFont("Poppins-SemiBold.ttf", "Poppins", "bold");
  registered = true;
  return registered;
}
